namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to database and create tables
  auto conn = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then(create_table<Course> | if_not_exists)
    .and_then(create_table<Enrollment> | if_not_exists);

  if (!conn) {
    return {};
  }

  // Execute the query with JOIN and GROUP BY
  auto result = conn.and_then([](auto connection) {
    // Perform LEFT JOIN query with aggregations
    const std::string query = R"(
      SELECT c.title, COUNT(e.enrollment_id) as student_count, AVG(e.grade) as avg_grade
      FROM Course c
      LEFT JOIN Enrollment e ON c.course_id = e.course_id
      GROUP BY c.course_id, c.title
    )";

    return connection.template execute_query<std::vector<CourseStatsView>>(query);
  });

  // Convert CourseStatsView to CourseStats
  if (!result) {
    return {};
  }

  std::vector<CourseStats> stats;
  for (const auto& view : result.value()) {
    stats.push_back(CourseStats{
      .title = view.title,
      .student_count = view.student_count,
      .avg_grade = view.avg_grade
    });
  }

  return stats;
}

}  // namespace query_course_enrollment_stats
