```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_employee_hierarchy {

struct Employee {
  sqlgen::PrimaryKey<int> emp_id;
  std::string name;
  std::optional<int> manager_id;
};

struct EmployeeManager {
  std::string employee;
  std::optional<std::string> manager;
};

std::vector<EmployeeManager> query_employee_hierarchy() {
    using namespace sqlgen;

    // Open connection to SQLite database
    auto db = sqlite::open("test_db.sqlite");

    // Execute self-join query to get employee and manager names
    // Using LEFT JOIN to include employees without managers (top-level employees)
    std::string sql = R"(
        SELECT e1.name as employee, e2.name as manager
        FROM Employee e1
        LEFT JOIN Employee e2 ON e1.manager_id = e2.emp_id
    )";

    // Execute query and map results to EmployeeManager struct
    auto results = db.query<EmployeeManager>(sql);

    return results;
}

}  // namespace query_employee_hierarchy
```

This implementation:

1. **Opens the database connection** to "test_db.sqlite" using `sqlite::open()`
2. **Performs a self-join** by aliasing the Employee table as `e1` (employee) and `e2` (manager)
3. **Uses LEFT JOIN** to include employees without managers - those with NULL manager_id will have NULL in the manager field
4. **Selects the appropriate columns** - e1.name as employee and e2.name as manager
5. **Maps results** to the `EmployeeManager` struct which has `std::optional<std::string> manager` to handle NULL values for top-level employees
6. **Returns** the vector of EmployeeManager records

The `std::optional<std::string>` for the manager field ensures that top-level employees (those without a manager) are handled gracefully with NULL/empty optional values.

