#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_product_sales_report {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen;

    // Connect to SQLite database
    auto conn = sqlgen::sqlite::Connection("test_db.sqlite");

    // Define the SQL query with JOIN, GROUP BY, and HAVING clause
    const std::string query = 
        "SELECT p.category, SUM(s.quantity) as total_qty, SUM(s.amount) as total_amt "
        "FROM Product p "
        "INNER JOIN Sale s ON p.product_id = s.product_id "
        "GROUP BY p.category "
        "HAVING total_amt > 5000";

    // Execute query and return results
    return conn.execute<std::vector<CategoryReport>>(query);
}

}  // namespace query_product_sales_report
```

This implementation:

1. **Connects to the SQLite database** `test_db.sqlite` using `sqlgen::sqlite::Connection`
2. **Defines the SQL query** that:
   - Joins the `Product` and `Sale` tables on `product_id`
   - Groups results by `category`
   - Calculates `SUM(quantity)` and `SUM(amount)` for each category
   - Filters categories with `total_amt > 5000` using the HAVING clause
3. **Executes the query** and maps results to `std::vector<CategoryReport>`
4. **Returns the results** containing category sales reports that meet the criteria

