ground truth:
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <optional>
#include <string>
#include <vector>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
  using namespace sqlgen;
  using namespace sqlgen::literals;
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return false;
  create_table<Document>(conn_res);

  auto txn_res = begin_transaction(conn_res.value());
  if (!txn_res) return false;
  auto txn = txn_res.value();

  for (int id : ids) {
    auto res = (update<Document>("is_deleted"_c.set(1)) |
                where("doc_id"_c == id))(txn->conn());
    if (!res) { (void)txn->rollback(); return false; }
  }

  auto commit_res = commit(txn);
  return commit_res.has_value();
}

}  // namespace soft_delete_records

test cases:
#include <gtest/gtest.h>
#include "soft_delete_records.hpp"

namespace soft_delete_records {

TEST(sqlite, soft_delete_records) {
  using namespace sqlgen;
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Document>(conn);
  create_table<Document>(conn);

  std::vector<Document> docs = {
      {1, "doc1", 0, std::nullopt},
      {2, "doc2", 0, std::nullopt},
      {3, "doc3", 0, std::nullopt}};
  insert(conn, docs);

  ASSERT_TRUE(soft_delete_records({1, 3}));
  auto rows = sqlgen::read<std::vector<Document>>(conn).value();

  auto find = [&](int id) {
    return std::find_if(rows.begin(), rows.end(),
                        [&](const Document& d) { return d.doc_id.value() == id; });
  };

  EXPECT_EQ(find(1)->is_deleted, 1);
  EXPECT_EQ(find(3)->is_deleted, 1);
  EXPECT_EQ(find(2)->is_deleted, 0);
}

}  // namespace soft_delete_records

