```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>
#include <sstream>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    if (ids.empty()) {
        return true;  // Nothing to delete
    }

    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn) {
        return false;
    }

    // Build UPDATE query with IN clause
    std::ostringstream query;
    query << "UPDATE Document SET is_deleted = 1, deleted_at = CURRENT_TIMESTAMP WHERE doc_id IN (";

    for (size_t i = 0; i < ids.size(); ++i) {
        if (i > 0) {
            query << ", ";
        }
        query << "?";
    }
    query << ")";

    // Execute the update statement
    auto result = conn.and_then([&](auto& c) {
        // Prepare the statement with all IDs as parameters
        auto stmt = c.prepare(query.str());
        if (!stmt) {
            return sqlgen::Result<void>(stmt.error());
        }

        // Bind all IDs
        for (size_t i = 0; i < ids.size(); ++i) {
            stmt.value().bind(i + 1, ids[i]);
        }

        return stmt.value().execute();
    });

    return result.has_value();
}

}  // namespace soft_delete_records
```

