  using namespace sqlgen::literals;

  auto conn = sqlite::connect(db_path);
  if (!conn) {
    throw std::runtime_error("Failed to connect to database");
  }

  exec(conn, "ALTER TABLE Score ADD COLUMN Grade CHAR(1) NOT NULL DEFAULT 'A';").value();

