```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Inserts the provided events into a temporary SQLite table, runs a query
 * to extract date/time parts and compute duration, and returns the results
 * as a vector of TemporalAnalysis.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  // Create SQLite connection to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Create the Event table if it doesn't exist
  sqlgen::execute(conn, sqlgen::CreateTable<Event>{});

  // Insert the events into the table
  if (!events.empty()) {
    sqlgen::execute(conn, sqlgen::Insert<Event>{events});
  }

  // Build the temporal analysis query using SQLite-specific date/time functions
  // SQLite uses strftime() for date component extraction and julianday() for date arithmetic
  const std::string sql = R"(
    SELECT 
      event_id,
      event_name,
      CAST(strftime('%d', start_time) AS INTEGER) as start_day,
      CAST(strftime('%m', start_time) AS INTEGER) as start_month,
      CAST(strftime('%Y', start_time) AS INTEGER) as start_year,
      CAST(strftime('%H', start_time) AS INTEGER) as start_hour,
      CAST(strftime('%M', start_time) AS INTEGER) as start_minute,
      CAST(strftime('%S', start_time) AS INTEGER) as start_second,
      CAST(strftime('%w', start_time) AS INTEGER) as start_weekday,
      CAST(strftime('%s', start_time) AS INTEGER) as start_epoch,
      julianday(end_time) - julianday(start_time) as duration_days
    FROM Event
    WHERE end_time IS NOT NULL
  )";

  // Execute the custom query and return the temporal analysis results
  return sqlgen::execute(conn, sqlgen::CustomQuery<TemporalAnalysis>{sql});
}

}  // namespace analyze_temporal_data
```

This implementation:

1. **Connects to SQLite database**: Creates a connection to "test_db.sqlite"
2. **Creates the Event table**: Uses `sqlgen::CreateTable<Event>{}` to ensure the table exists
3. **Inserts events**: Uses `sqlgen::Insert<Event>{events}` to populate the table with the provided events
4. **Executes temporal analysis**: Uses a custom SQL query with SQLite-specific functions:
   - `strftime('%d', ...)` - extracts day (01-31)
   - `strftime('%m', ...)` - extracts month (01-12)
   - `strftime('%Y', ...)` - extracts year
   - `strftime('%H', ...)` - extracts hour (00-23)
   - `strftime('%M', ...)` - extracts minute (00-59)
   - `strftime('%S', ...)` - extracts second (00-59)
   - `strftime('%w', ...)` - extracts weekday (0-6, Sunday=0)
   - `strftime('%s', ...)` - converts to Unix epoch timestamp
   - `julianday()` - calculates date differences in days
5. **Returns results**: Returns a vector of `TemporalAnalysis` structs with comprehensive temporal information for all events that have an `end_time`

