struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlite::Connection("test_db.sqlite");

  // 1. Create tables for User and Friendship
  conn.execute(CreateTable<User>{});
  conn.execute(CreateTable<Friendship>{});

  // Insert user data
  if (!users.empty()) {
    conn.execute(Insert(users));
  }

  // Insert friendship data
  if (!friendships.empty()) {
    conn.execute(Insert(friendships));
  }

  std::vector<FriendConnection> results;

  // 2. Use SELF-JOIN to find mutual friends
  // Find pairs of users who are connected through friendships
  // This query finds direct friend connections
  auto direct_friends_query = Select(
    "u1"_alias / &User::username,
    "u2"_alias / &User::username
  )
  .From(As<User>("u1"))
  .Join(As<Friendship>("f"), "f"_alias / &Friendship::user1_id == "u1"_alias / &User::user_id)
  .Join(As<User>("u2"), "u2"_alias / &User::user_id == "f"_alias / &Friendship::user2_id)
  .Where("u1"_alias / &User::user_id < "u2"_alias / &User::user_id);

  auto direct_result = conn.execute(direct_friends_query);

  for (const auto& row : direct_result) {
    FriendConnection fc;
    fc.user1_name = std::get<0>(row);
    fc.user2_name = std::get<1>(row);
    results.push_back(fc);
  }

  // 3. Find friend-of-friend relationships (people connected through exactly one mutual friend)
  // Using SELF-JOIN to find mutual connections
  auto fof_query = Select(
    "u1"_alias / &User::username,
    "u3"_alias / &User::username
  )
  .From(As<User>("u1"))
  .Join(As<Friendship>("f1"), "f1"_alias / &Friendship::user1_id == "u1"_alias / &User::user_id)
  .Join(As<Friendship>("f2"), "f2"_alias / &Friendship::user1_id == "f1"_alias / &Friendship::user2_id)
  .Join(As<User>("u3"), "u3"_alias / &User::user_id == "f2"_alias / &Friendship::user2_id)
  .Where("u1"_alias / &User::user_id != "u3"_alias / &User::user_id);

  auto fof_result = conn.execute(fof_query);

  for (const auto& row : fof_result) {
    FriendConnection fc;
    fc.user1_name = std::get<0>(row);
    fc.user2_name = std::get<1>(row);
    results.push_back(fc);
  }

  // 4. Count friends per user and identify most connected users
  // Using aggregation with GROUP BY
  auto friend_count_query = Select(
    "u"_alias / &User::username,
    Count("f"_alias / &Friendship::user2_id)
  )
  .From(As<User>("u"))
  .LeftJoin(As<Friendship>("f"), "f"_alias / &Friendship::user1_id == "u"_alias / &User::user_id)
  .GroupBy("u"_alias / &User::user_id, "u"_alias / &User::username)
  .OrderBy(Desc(Count("f"_alias / &Friendship::user2_id)));

  auto count_result = conn.execute(friend_count_query);

  // Process aggregation results (optional - can be used for analysis)

  return results;
}

}  // namespace analyze_social_network
