```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // SQLite doesn't support FULL OUTER JOIN natively, so we simulate it using UNION
  // This combines:
  // 1. All suppliers with their matching products (or NULL if no products)
  // 2. All products without matching suppliers
  const std::string full_join_query = R"(
    SELECT s.name as supplier_name, p.name as product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION ALL
    SELECT '' as supplier_name, p.name as product_name
    FROM Product p
    WHERE NOT EXISTS (
      SELECT 1 FROM Supplier s WHERE s.supplier_id = p.supplier_id
    )
  )";

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then([&full_join_query](auto connection) {
      return connection.template query<std::vector<SupProd>>(full_join_query);
    });

  return result.value_or(std::vector<SupProd>{});
}

}  // namespace full_join_suppliers_products
```

This implementation:

1. **Connects to the database**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to connect to the specified SQLite database.

2. **Simulates FULL JOIN**: Since SQLite doesn't natively support FULL OUTER JOIN, the query uses `UNION ALL` to combine:
   - A LEFT JOIN from Supplier to Product (gets all suppliers and their matching products)
   - Products without matching suppliers (using a NOT EXISTS clause)

3. **Returns all rows**: The result includes:
   - All suppliers with their products (product_name filled)
   - All suppliers without products (product_name is NULL)
   - All products without matching suppliers (supplier_name is empty string, product_name filled)

4. **Error handling**: Uses `value_or()` to return an empty vector if the query fails.

