      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "INNER JOIN Employee e ON d.department_id = e.department_id";

  analysis.inner_join_results = conn
      .and_then(sqlgen::query(inner_join_sql))
      .and_then(sqlgen::read<std::vector<JoinResult>>)
      .value_or(std::vector<JoinResult>{});

  // LEFT JOIN: Include all employees (even without departments)
  auto left_join_sql = 
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id";

  analysis.left_join_results = conn
      .and_then(sqlgen::query(left_join_sql))
      .and_then(sqlgen::read<std::vector<JoinResult>>)
      .value_or(std::vector<JoinResult>{});

  // RIGHT JOIN: Include all departments (even without employees)
  // SQLite doesn't support RIGHT JOIN, so simulate with LEFT JOIN and swapped tables
  auto right_join_sql = 
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id";

  analysis.right_join_results = conn
      .and_then(sqlgen::query(right_join_sql))
      .and_then(sqlgen::read<std::vector<JoinResult>>)
      .value_or(std::vector<JoinResult>{});

  // FULL JOIN: Include all employees and departments
  // SQLite doesn't support FULL JOIN, so simulate with UNION of LEFT JOINs
  auto full_join_sql = 
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id "
      "UNION "
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id";

  analysis.full_join_results = conn
      .and_then(sqlgen::query(full_join_sql))
      .and_then(sqlgen::read<std::vector<JoinResult>>)
      .value_or(std::vector<JoinResult>{});

  return analysis;
}

}  // namespace analyze_department_employees

