  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database and execute the query
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then([limit_count](auto db) {
      // Build and execute query: JOIN Product and Sales tables,
      // calculate total sales, group by product, order by total sales DESC,
      // and apply limit
      return sqlgen::select<TopProduct>(
        "p.product_id"_c,
        "p.product_name"_c,
        "p.category"_c,
        sum("p.price"_c * "s.quantity"_c) | as("total_sales"_c)
      )
      | from<Product>("p"_c)
      | inner_join<Sales>("s"_c) | on("p.product_id"_c == "s.product_id"_c)
      | group_by("p.product_id"_c, "p.product_name"_c, "p.category"_c)
      | order_by(desc("total_sales"_c))
      | limit(limit_count)
      | execute(db);
    });

  // Return results or empty vector if query failed
  return result.value_or(std::vector<TopProduct>{});
}

}  // namespace get_top_products
