#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;

  // Connect to SQLite database
  auto db = sqlite::open("test_db.sqlite");

  // Execute query with temporal operations using SQLite-specific functions
  // SQLite uses strftime() for date/time component extraction
  // and julianday() for date difference calculations
  const auto results = db.template query<TimeMetrics>(R"(
    SELECT p.project_id, p.name,
           CAST(strftime('%d', t.start_time) AS INTEGER) as day,
           CAST(strftime('%m', t.start_time) AS INTEGER) as month,
           CAST(strftime('%Y', t.start_time) AS INTEGER) as year,
           CAST(strftime('%H', t.start_time) AS INTEGER) as hour,
           CAST(strftime('%M', t.start_time) AS INTEGER) as minute,
           CAST(strftime('%S', t.start_time) AS INTEGER) as second,
           julianday(t.end_time) - julianday(t.start_time) as duration_days
    FROM Project p
    INNER JOIN TimeLog t ON p.project_id = t.project_id
  )");

  return results;
}

}  // namespace project_time_tracking
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlite::open("test_db.sqlite")` to connect to the SQLite database.

2. **SQLite Temporal Functions**: 
   - `strftime('%d', t.start_time)` - extracts day
   - `strftime('%m', t.start_time)` - extracts month
   - `strftime('%Y', t.start_time)` - extracts year
   - `strftime('%H', t.start_time)` - extracts hour
   - `strftime('%M', t.start_time)` - extracts minute
   - `strftime('%S', t.start_time)` - extracts second
   - `julianday(t.end_time) - julianday(t.start_time)` - computes days between timestamps

3. **Type Casting**: Results are cast to INTEGER for the time components to match the `int` type in `TimeMetrics`.

4. **JOIN Operation**: Performs an INNER JOIN between Project and TimeLog tables on `project_id`.

5. **Result Mapping**: The `query<TimeMetrics>()` template method automatically maps the SQL results to the `TimeMetrics` struct.

