 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto db = sqlite::open("test_db.sqlite");

  // Get table references
  auto user_table = db.table<User>("User");
  auto post_table = db.table<Post>("Post");

  // Build query with join, aggregations, and group by
  auto results = db.query<Stats>()
    .select(user_table.user_id, 
            user_table.name,
            count(post_table.post_id).as("post_count"_name),
            avg(length(post_table.content)).as("avg_length"_name))
    .from(user_table)
    .left_join(post_table).on(user_table.user_id == post_table.user_id)
    .group_by(user_table.user_id, user_table.name)
    .execute();

  return results;
}

